module dram_cell (  
    input [15:0] data_in,  
    input RE,  
    input WE,  
    input CLK,  
    output reg [15:0] data_out  
);  
    reg [15:0] unused_memory;  

    always @(posedge CLK) begin  
        if (WE)  
            unused_memory <= data_in;  
        if (RE)  
            data_out <= unused_memory;  
    end  
endmodule
